import { registerMvuSchema } from 'https://testingcf.jsdelivr.net/gh/StageDog/tavern_resource/dist/util/mvu_zod.js';

export const Schema = z.object({
  世界: z.object({
    当前周期: z.coerce.number().prefault(1),
    斩杀线: z.coerce.number().prefault(100),
    系统警报: z.coerce.number().prefault(0),
    日期: z.string().prefault('第1周期 - 第1天'),
    天气: z.string().prefault('雾霾')
  }).prefault({}),

  玩家: z.object({
    Cash_HP: z.coerce.number().prefault(500),
    麻木指数: z.coerce.number().prefault(10),
    焦虑值: z.coerce.number().prefault(20),
    饥饿度: z.coerce.number().prefault(20),
    欲望阈值: z.coerce.number().prefault(0),
    基底侵蚀度: z.coerce.number().prefault(0),
    身体开发度: z.coerce.number().prefault(0),
    性别: z.string().prefault('女性'),
    敏感度: z.coerce.number().prefault(150),
    // 降维打击：直接用纯文本记录状态！
    状态标签: z.string().prefault('无')
  }).prefault({}),

  手牌: z.record(
    z.object({
      名称: z.string().prefault(''),
      类型: z.string().prefault('生存'),
      描述: z.string().prefault(''),
      消耗: z.string().prefault(''),
      效果: z.string().prefault('')
    })
  ).prefault({}),

  待结算债务: z.record(
    z.object({
      名称: z.string().prefault(''),
      剩余回合: z.coerce.number().prefault(0),
      惩罚效果: z.string().prefault('')
    })
  ).prefault({}),

  NPC: z.object({
    便利店员: z.object({
      信任度: z.coerce.number().prefault(5),
      关系阶段: z.string().prefault('陌生'),
      特殊事件标记: z.string().prefault('无')
    }).prefault({}),
    算法中介: z.object({
      评分: z.coerce.number().prefault(60),
      警惕值: z.coerce.number().prefault(0)
    }).prefault({})
  }).prefault({}),

  统计: z.object({
    存活天数: z.coerce.number().prefault(0),
    总服务次数: z.coerce.number().prefault(0),
    违规次数: z.coerce.number().prefault(0)
  }).prefault({})
});

$(() => {
  registerMvuSchema(Schema);
});

