                        const m = parseInt(match[1]);
                        const s = parseInt(match[2]);
                        const ms = parseInt(match[3]);
                        const time = m * 60 + s + ms / 100;
                        const text = line.replace(timeReg, '').trim();
                        if(text) result.push({ time, text });
