            audio.addEventListener('timeupdate', () => {
                const currentTime = audio.currentTime;

                // 更新进度条
                const percent = (currentTime / audio.duration) * 100;
                progressBar.style.width = percent + '%';
                timeDisplay.textContent = formatTime(currentTime) + ' / ' + formatTime(audio.duration);

                if(parsedLyrics.length === 0) return;

                // 寻找当前时间对应的歌词行
                let newIndex = -1;
                for (let i = 0; i < parsedLyrics.length; i++) {
                    if (currentTime >= parsedLyrics[i].time) {
                        newIndex = i;
                    } else {
                        break;
                    }
                }

                // 行数改变，更新三个div的文本，触发特效
                if (newIndex !== -1 && newIndex !== currentLineIndex) {
                    currentLineIndex = newIndex;

                    elPrev.textContent = newIndex > 0 ? parsedLyrics[newIndex - 1].text : "";
                    elCurr.textContent = parsedLyrics[newIndex].text;
