            const cards = document.querySelectorAll('.cyber-card-item');
            cards.forEach(card => {
                const typeEl = card.querySelector('.raw-type');
                if(!typeEl) return;
                const typeText = typeEl.innerText;

                // 强制/H类标红
                if(typeText.includes('强制') || typeText.includes('H') || typeText.includes('失控') || typeText.includes('灰色')) {
                    card.classList.add('card-type-danger');
                    typeEl.style.background = 'rgba(255,0,60,0.2)';
                    typeEl.style.color = '#ff003c';
                    typeEl.style.borderColor = '#ff003c';
                }
                // 工作类标橙
                else if(typeText.includes('工作') || typeText.includes('生存')) {
                    card.classList.add('card-type-work');
                    typeEl.style.background = 'rgba(255,170,0,0.2)';
                    typeEl.style.color = '#ffaa00';
                    typeEl.style.borderColor = '#ffaa00';
                }
            });
        })();

        // 点击卡牌触发交互
        function selectCyberCard(element) {
            const cardName = element.getAttribute('data-name');
            const hasTriggerSlash = typeof triggerSlash === 'function';

            if (hasTriggerSlash) {
                // 点击后直接以玩家身份发送选择内容并触发AI回复
                const command = `/echo severity=success 已确认执行指令：[${cardName}] | /send 我选择执行 [${cardName}] | /trigger`;
                triggerSlash(command);
            } else {
                alert(`系统提示：未检测到STscript接口。请手动输入选择：[${cardName}]`);
            }
        }
